// ── ASSETS ──
const STAR_SRC = `data:image/png;base64,`;

// ── CURSOR ──
const cursor = document.getElementById('cursor');
let lastTrailTime = 0;

document.addEventListener('mousemove', (e) => {
  cursor.style.left = e.clientX + 'px';
  cursor.style.top  = e.clientY + 'px';

  const el = document.elementFromPoint(e.clientX, e.clientY);
  const isDark = el && !!el.closest('#servicios, #devlog, footer');
  cursor.classList.toggle('on-dark', isDark);

  const now = Date.now();
  if (now - lastTrailTime > 90) {
    createTrail(e.clientX, e.clientY, isDark);
    lastTrailTime = now;
  }
});

function createTrail(x, y, isDark) {
  const trail = document.createElement('div');
  trail.classList.add('trail');
  trail.style.left = x + 'px';
  trail.style.top  = y + 'px';
  const size = Math.random() * 14 + 8;
  const f = isDark ? 'filter:invert(1) brightness(2) sepia(1) hue-rotate(10deg) saturate(3)' : '';
  trail.innerHTML = `<img src="${STAR_SRC}" style="width:${size}px;height:${size}px;${f}">`;
  document.body.appendChild(trail);
  setTimeout(() => trail.remove(), 1400);
}

// ── NAV COLOR ──
const nav = document.getElementById('nav');

function updateNav() {
  const scrollY = window.scrollY;
  let isDark = false;
  ['servicios', 'devlog'].forEach(id => {
    const el = document.getElementById(id);
    if (el) {
      const top = el.offsetTop - 72;
      if (scrollY >= top && scrollY < top + el.offsetHeight) isDark = true;
    }
  });
  nav.classList.toggle('dark', isDark);
}
window.addEventListener('scroll', updateNav, { passive: true });
updateNav();

// ── STICKER DRAG (restringido al hero) ──
const sticker      = document.getElementById('sticker');
const stickerLabel = document.getElementById('stickerLabel');
const hero         = document.getElementById('inicio');
let isDragging = false;
let offsetX = 0, offsetY = 0;
let hasMoved = false;

sticker.addEventListener('mousedown', (e) => {
  isDragging = true;
  const rect = sticker.getBoundingClientRect();
  offsetX = e.clientX - rect.left;
  offsetY = e.clientY - rect.top;
  sticker.classList.add('dragging');
  sticker.classList.remove('placed');
  e.preventDefault();
});

document.addEventListener('mousemove', (e) => {
  if (!isDragging) return;

  const heroRect  = hero.getBoundingClientRect();
  const stickerW  = sticker.offsetWidth;
  const stickerH  = sticker.offsetHeight;
  const margin    = 16;

  let newLeft = e.clientX - heroRect.left - offsetX;
  let newTop  = e.clientY - heroRect.top  - offsetY;

  newLeft = Math.max(margin, Math.min(newLeft, heroRect.width  - stickerW - margin));
  newTop  = Math.max(margin, Math.min(newTop,  heroRect.height - stickerH - margin));

  sticker.style.right     = 'auto';
  sticker.style.left      = newLeft + 'px';
  sticker.style.top       = newTop  + 'px';
  sticker.style.transform = 'rotate(3deg)';

  if (!hasMoved) {
    hasMoved = true;
    stickerLabel.style.opacity = '0';
  }
});

document.addEventListener('mouseup', () => {
  if (!isDragging) return;
  isDragging = false;
  sticker.classList.remove('dragging');
  sticker.classList.add('placed');
});

// ── SCROLL REVEAL ──
const revealObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      revealObserver.unobserve(entry.target);
    }
  });
}, { threshold: 0.1 });

document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));

// ── FORMULARIO ──
function handleSubmit(e) {
  e.preventDefault();
  const btn = e.target.querySelector('.btn-send');
  btn.textContent = 'Mensaje enviado ✦';
  btn.style.opacity = '0.6';
  setTimeout(() => {
    btn.textContent  = 'Enviar mensaje';
    btn.style.opacity = '1';
    e.target.reset();
  }, 3000);
}
